const r={name:"Körsbär",icon:"korsbar",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"30-80+ år",difficulty:"Medel",difficultyWhy:"Kräver beskärning under rätt period (JAS - aldrig vinter!), fågelskydd vid skörd och viss sjukdomskontroll. Men ett etablerat körsbärsträd ger fantastisk skörd i decennier. Surkörsbär är enklare än sötkörsbär.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Sötkörsbär på svagväxande grundstam (Gisela) 3-4 m, surkörsbär (buskform) 2-3 m",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Samma princip som äpple och päron - ympstället ska aldrig hamna under jord",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Körsbär vill ha minst 6-8 timmars direkt sol. Sötkörsbär kräver det bästa läget du har - sydvänd, skyddad plats. Surkörsbär är mer skuggtåliga och klarar halvskugga."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"Behöver vinterkyla (600-1000 kylltimmar under 7°C) för att bryta vila. Körsbär blommar TIDIGT på våren - vårfrost är den absolut största fienden. En enda frostnatt under blomning och skörden är körd."},wind:{level:"Skyddat",detail:"Vindskydd under blomning är avgörande - kall vind skrämmer bort pollinatörer och skadar ömtåliga blommor. Sluttningar med god luftcirkulation är perfekt (undviker frostfickor)."}},watering:{need:"Medel",icon:"water",summary:"Etablerade körsbärsträd klarar sig oftast på regnvatten. Nyplanterade träd behöver regelbunden vattning de första 2-3 åren. Ojämn vattning under fruktmognad ger sprickor.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - torrt och kallt väder ger dålig pollinering och liten skörd."},{phase:"Sommar (fruktmognad)",need:"Medel",tip:"Vattna jämnt under fruktmognad. Plötsligt regn efter torka = sprickta körsbär. Det är fruktodlarens mardröm."},{phase:"Efterskörd",need:"Låg",tip:"Minska vattningen efter skörd. Trädet bygger energi för nästa år."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Ingen vattning behövs."}],mistakes:["Glömmer att vattna nyplanterade träd första somrarna","Ojämn vattning under fruktmognad - ger sprickta körsbär","Vattnar sent på hösten - stimulerar sen tillväxt som inte hinner mogna före frost"],tip:"Mulcha med gräsklipp eller kompost runt trädet (inte intill stammen). Jämn markfukt minskar risken för sprickta körsbär dramatiskt."},soil:"Körsbär vill ha väldränerad, kalkrik jord. De tål INTE vattensjuk mark - stående vatten dödar rötterna snabbare än kyla. En lätt, mullrik jord på en sluttning är drömmen.",soilTips:["Kalka om pH är under 6.0 - körsbär älskar kalk","Undvik blöta svackor och mark med hög grundvattennivå","Blanda in kompost i planteringsgropen (max 1/3)","På tung lera: plantera upphöjt för bättre dränering"],timeline:{1:[{phase:"Blomning",months:"April-maj",icon:"bloom"},{phase:"Fruktmognad",months:"Juni-aug",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Okt-nov",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],4:[{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktmognad",months:"Juli-aug",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-sept",icon:"scissors"},{phase:"Höstplantering",months:"Sept-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Sommarbeskärning (JAS)",months:"Juli-aug",icon:"scissors"},{phase:"Höstplantering",months:"Sept-okt",icon:"seedling"},{phase:"Vintervila",months:"Okt-april",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:3,label:"Blomning"},{month:"Jun",N:6,P:5,K:5,label:"Fruktsättning"},{month:"Jul",N:4,P:4,K:7,label:"Mognad"},{month:"Aug",N:2,P:2,K:5},{month:"Sep",N:1,P:1,K:3}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Körsbär är inte extremt näringskrävande - övergödsel ger frodigt bladverk men dålig frukt."},{timing:"Blomning (maj)",tip:"En liten giva vedaska (kaliumrik) stärker blomning och fruktsättning."},{timing:"Efter skörd",tip:"Ingen extra gödsel behövs. Mulcha med gräsklipp för långsam näringsfrisättning."},{timing:"Höst",tip:"Ingen kvävegödsling efter midsommar - nya skott ska hinna mogna och härda före vintern."}],companions:{good:[{name:"Kaprifol",icon:"flower",why:"Lockar pollinatörer tidigt på våren - avgörande för körsbär som blommar innan de flesta andra fruktträd."},{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter. Perfekt som underplantering."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt fruktträd. Lökdoften avskräcker vissa skadeinsekter."},{name:"Klöver",icon:"flower",why:"Fixerar kväve och täcker marken. Lockar humlor som pollinerar körsbärsblommorna."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Ökar risken för rotröta (Phytophthora) som kan skada trädets rotsystem."},{name:"Gräsmatta ända intill stammen",icon:"vegetable",why:"Gräs konkurrerar om vatten och näring. Håll en meter fritt runt stammen med mulch istället."}]},rotation:{avoid:[{name:"Körsbär"},{name:"Plommon"},{name:"Päron"},{name:"Äpple"}],avoidWhy:"Plantera aldrig ett nytt körsbärsträd där ett gammalt Prunus-träd stått - trötthetssjuka (replant disease) gör att det nya trädet aldrig riktigt trivs. Svampsporer och näringsbrister i jorden saboterar etableringen. Vänta minst 5 år eller välj en annan plats.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats i flera år ger den bästa starten.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Om ett gammalt träd tas bort, gröngödsla marken i minst 3-5 år innan du planterar ett nytt fruktträd."},varieties:[{name:"Gårdebo",zones:[1,2,3,4,5],note:"Sötkörsbär. Grönt kulturarv E-planta från Tranås, Småland. En av de härdigaste sötkörsbären. Liten, mörkröd, söt och saftig frukt. Sannolikt självfertil."},{name:"Fryksås",zones:[1,2,3,4,5],note:"Sötkörsbär. Grönt kulturarv E-planta från Dalarna. Gulröd hjärtformad bigarrå med saftigt fruktkött. Sannolikt självfertil. Mognar sent augusti."},{name:"Stella",zones:[1,2,3],note:"Sötkörsbär. Kanadensisk klassiker. Stor, mörkröd bigarrå. Helt självfertil och dessutom utmärkt pollengivare för andra sorter. Den säkra nybörjarsorten."},{name:"Sunburst",zones:[1,2,3,4],note:"Sötkörsbär. Korsning Van x Stella. Stor, mörkröd till nästan svart, mycket söt. Självfertil. Tidig mognad (mitten juli)."},{name:"Stor Svart Bigarrå",zones:[1,2,3],note:"Sötkörsbär. Grönt kulturarv. Gammal sort (möjligen 1500-tal). Stora, svartröda, otroligt söta dessertkörsbär. Kräver pollinatör."},{name:"Skuggmorell",zones:[1,2,3,4,5],note:"Surkörsbär. E-planta. Stora, mörkt brunröda bär med syrlig smak. Helt självfertil. Perfekt för saft, sylt och paj. Den mest odlingsvärda surkörsbärssorten."},{name:"Nordia",zones:[1,2,3,4,5,6],note:"Surkörsbär. Svensk sort från SLU Balsgård. Kompakt buskform (2-3 m). Extremt härdig. Självfertil. Mörkröd, syrlig frukt för saft och sylt."},{name:"Lettisk Låg",zones:[1,2,3,4,5,6],note:"Surkörsbär. Buskform, bara ca 2 meter. Extremt härdig. Självfertil. Tidig mognad. Passar balkong och liten trädgård."}],problems:[{name:"Monilia/Blom- och grentorka (Monilinia laxa)",symptom:"Blommor och unga skott vissnar och svartnar som bränts. Mumifierade frukter hänger kvar på grenarna. Värst i fuktigt väder under blomning.",fix:"Skär bort angripna delar minst 20 cm in i frisk ved. Plocka bort ALLA fruktmumier - de sprider sporer nästa vår. Håll kronan öppen och luftig."},{name:"Silversjuka (Chondrostereum purpureum)",symptom:"Bladen får silveraktig metallglans, först i enstaka grenar. Sjukdomen sprids via sår - särskilt vinterbeskärningssår!",fix:"Beskär ALDRIG körsbär på vintern! JAS-perioden (juli-aug-sept) är enda rätta tiden. Sår torkar snabbt på sommaren och risken för infektion sjunker dramatiskt."},{name:"Körsbärsfluga (Rhagoletis cerasi)",symptom:"Larver i frukterna som äter fruktköttet inifrån. Upptäcks ofta först vid skörd.",fix:"Finmaskigt insektsnät över trädet innan frukterna börjar färgas. Plocka upp fallfrukt. Biologisk bekämpning med nyttosvampar (Beauveria bassiana) finns."},{name:"Fåglar",symptom:"Koltrastar, starar och sidensvans äter upp hela skörden innan du hinner reagera. De börjar redan när körsbären är halvmogna.",fix:"Bärnät är enda riktigt effektiva skyddet. Täck trädet INNAN bären börjar rodna. Fågelskrämmor fungerar bara tillfälligt - fåglarna vänjer sig. Välj dvärgträd som är enklare att nättäcka."}],pollination:{selfFertile:!1,description:"Sötkörsbär är ofta självsterila och behöver en pollinationspartner. Surkörsbär är däremot nästan alltid självfertila. Om du bara har plats för ett träd: välj en självfertil sort (Stella, Sunburst, Gårdebo) eller ett surkörsbär. Två olika sorter ger alltid bättre skörd, även hos självfertila sorter.",groups:[{name:"Självfertila sötkörsbär",varieties:["Stella","Sunburst","Lapins","Gårdebo","Fryksås"]},{name:"Kräver pollinatör (sötkörsbär)",varieties:["Stor Svart Bigarrå","Hedelfinger","Van","Regina"]},{name:"Surkörsbär (alla självfertila)",varieties:["Skuggmorell","Nordia","Lettisk Låg","Fanal","Kellerris 16"]}],tip:"Surkörsbär pollinerar faktiskt sötkörsbär! En Skuggmorell är en utmärkt partner till ett sötkörsbärsträd. Två flugor i en smäll - du får körsbär för direkt ätning OCH för saft och sylt."},establishment:{description:"Körsbärsträd etablerar sig snabbt jämfört med andra fruktträd. Ge dem en bra start de första åren så belönar de dig med riklig skörd.",years:[{year:"År 1",tasks:["Vattna 20-30 liter per vecka hela första sommaren","Plocka bort ALL frukt som sätts - trädet ska bygga rötter","Kontrollera att stödbindningen sitter lagom löst","Mulcha i 1 meters radie runt stammen (inte intill stammen!)"]},{year:"År 2",tasks:["Första formande beskärning under JAS-perioden (juli-sept)","Fortsätt vattna vid torka","Tillåt en liten skörd (5-10 frukter)","Gödsla försiktigt med kompost på våren"]},{year:"År 3-5",tasks:["Årlig JAS-beskärning: öppna kronan, ta bort vattenskott","Öka tillåten skörd gradvis - full skörd år 4-5 (dvärgträd)","Montera fågelnät inför skörd","Trädet blir alltmer självgående"]}],protection:["Stamskydd mot gnagare (nät eller spiral) - kaniner och sorkar gnager bark","Viltskydd om rådjur finns i området","Stammskydd mot solbränna (vit kalkmjölk) på sydvästra sidan vintertid","Fågelnät - planera för detta redan vid val av grundstam (dvärgträd är enklare att skydda)"],tip:"Välj dvärgträd på Gisela-grundstam om du har en liten trädgård. De blir 2-4 meter, bär frukt redan år 2-3 och går att nättäcka mot fåglar. Ett fullstort körsbärsträd (8-12 m) är vackert men praktiskt omöjligt att skydda."},ripeningGuide:{description:"Körsbär mognar från juni till september beroende på sort och typ. Sötkörsbär äts färska direkt från trädet, surkörsbär används till saft, sylt och paj. Tiderna gäller zon 1-3 - räkna 2-4 veckor senare i norr.",entries:[{variety:"Sunburst",from:"jul",to:"jul",type:"Tidigt sötkörsbär"},{variety:"Stella",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Gårdebo",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Stor Svart Bigarrå",from:"jul",to:"aug",type:"Sötkörsbär"},{variety:"Fryksås",from:"aug",to:"aug",type:"Sent sötkörsbär"},{variety:"Fanal",from:"jul",to:"aug",type:"Surkörsbär"},{variety:"Lettisk Låg",from:"jul",to:"jul",type:"Tidigt surkörsbär"},{variety:"Skuggmorell",from:"aug",to:"aug",type:"Surkörsbär"},{variety:"Nordia",from:"aug",to:"aug",type:"Sent surkörsbär"}],tip:"Plocka körsbär med stjälk! Det ger längre hållbarhet och minskar risken för mögel. Sötkörsbär ska ätas samma dag eller inom 2-3 dagar. Surkörsbär håller lite längre och kan fryses direkt."},goodToKnow:[{icon:"warning",title:"Beskär ALDRIG på vintern!",text:"Den viktigaste regeln för körsbär: beskär bara under JAS-perioden (juli-aug-sept). Vinterbeskärning ger silversjuka - en svampinfektion som tar sig in via snitten och som det inte finns botemedel mot. Snitten torkar dåligt i kall, fuktig väderlek.",severity:"warning"},{icon:"warning",title:"Fåglarna vinner om du inte skyddar",text:"Det är inte en fråga om ifall fåglarna hittar dina körsbär, utan när. Koltrastar, starar och sidensvans kan tömma ett helt träd på en dag. Enda riktiga skyddet är bärnät - häng det INNAN bären börjar rodna.",severity:"warning"},{icon:"tip",title:"Surkörsbär - den underskattade hjälten",text:"Alla drömmer om söta körsbär, men surkörsbär (Skuggmorell, Nordia) är egentligen smartare: de är härdigare, alltid självfertila, mindre fågelkänsliga och ger fantastisk saft, sylt och paj. Dessutom pollinerar de sötkörsbär!",severity:"tip"},{icon:"tip",title:"Dvärgträd - framtidens körsbärsodling",text:"Moderna dvärggrundstammar (Gisela 5) ger körsbärsträd på 2-4 meter som bär frukt redan år 2-3. Lättare att beskära, nättäcka mot fåglar och skörda. Perfekt för villaträdgården.",severity:"tip"},{icon:"warning",title:"Akta frostfickor",text:"Körsbär blommar tidigt - ofta redan i april-maj. En enda frostnatt under blomning förstör hela skörden. Plantera ALDRIG i en svacka där kall luft samlas. En sluttning med god luftcirkulation är idealisk.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Körsbärsträd planteras som ympade träd. Barrotade träd planteras på hösten för bäst etablering. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen med mjuk bindning","Mulcha en cirkel på 1 meters radie runt stammen"],tips:["Höstplantering ger bäst etablering - rötterna växer hela vintern","Välj svagväxande grundstam (Gisela 5) för en hanterbar trädstorlek","Tänk på pollinering: behöver du en partner, eller väljer du en självfertil sort?","Plantera i en sluttning om möjligt - aldrig i en frostficka"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Körsbärsträd förökas genom ympning. Att så kärnor ger ett helt nytt träd med okända egenskaper - kul som experiment men vänta 8-15 år på skörd.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (Gisela 5 för dvärgträd, fågelbär för fullstort)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 2-4 år på första skörd"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Gå en ympkurs! Lokala trädgårdsföreningar arrangerar kurser varje vår. Kulturarvssorter som Gårdebo och Fryksås kan vara svåra att hitta i handeln men finns som ympkvistar via pomologiska föreningar."},storage:{shelfLife:"2-7 dagar (färska), 1+ år (förädlade)",methods:[{method:"Färska i kyl",icon:"cellar",duration:"3-7 dagar",description:"Sötkörsbär håller bara några dagar i kyl. Plocka med stjälk, sprid ut i tunnt lager. Tvätta inte förrän du ska äta dem.",best:!0},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Bästa sättet att bevara körsbär. Kärna ur, sprid ut på bakplåt och frys. Flytta till påsar. Perfekt till pajer, smoothies och glass.",best:!1},{method:"Saft och sylt",icon:"storage",duration:"1+ år",description:"Surkörsbärssaft är en svensk klassiker. Koka ur med socker, sila och häll på flaskor. Körsbärssylt med en gnutta mandelessens - gudomligt!",best:!1},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Kärna ur och torka i ugn (50°C, 8-10 timmar). Torkade körsbär är fantastiskt snacks och i müsli.",best:!1}],tips:["Sötkörsbär ska ätas snabbt - de tappar smak för varje dag i kylen","Plocka alltid med stjälk - körsbär utan stjälk möglar snabbare","Surkörsbär (Skuggmorell) är gjorda för saft - den bästa saften du kan göra","Frysta körsbär funkar utmärkt i matlagning men tappar sin krispighet"]},harvestCalc:{minPerSqm:5,maxPerSqm:30,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (den ENDA rätta tiden)",when:"Juli-augusti-september",description:"Körsbär och alla Prunus-arter ska BARA beskäras under JAS-perioden. Snitten torkar snabbt i sommarens värme och risken för silversjuka (Chondrostereum purpureum) sjunker dramatiskt. Vinterbeskärning är den vanligaste orsaken till silversjuka.",steps:["Ta bort döda, sjuka och korsande grenar","Ta bort rakt uppåtväxande vattenskott","Öppna kronan för ljus och luftcirkulation","Korta in årets skott till 3-4 blad","Desinficera verktygen mellan varje träd (Pseudomonas sprids via redskap)","Ta aldrig bort mer än 1/4 av kronvolymen per år"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"Kvist från önskad sort fästs på grundstam (Gisela 5 för dvärgträd, fågelbär/Prunus avium för fullstort). Kopulationsympning på våren eller ögonympning i augusti.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera körsbärskärnor i kylskåp i 10-12 veckor, så i kruka. Du får ett unikt träd, men det tar 8-15 år till skörd. Fågelbär (Prunus avium) från frö ger bra grundstammar.",icon:"seed"}],tip:"Surkörsbär (Prunus cerasus) bildar rotskott som kan användas som nya plantor - det enklaste sättet att föroka dem. Gräv upp ett rotskott med rötter och plantera på ny plats."}};export{r as korsbar};
